const QUESTIONS = [
  // === CATEGORÍA: Organización ===
  {cat:"Organización",q:"¿Qué significa AMZL?",a:"Amazon Logistics",opts:["Amazon Logistics","Amazon Last Zone","Amazon Load Management","Amazon Line"],explain:"AMZL es la red logística de última milla de Amazon. Se encarga de llevar los paquetes desde los centros de distribución hasta la puerta del cliente."},
  {cat:"Organización",q:"¿Qué es un HUB en AMZL?",a:"Centro de despacho de paquetes para última milla",opts:["Centro de despacho de paquetes para última milla","Almacén de devoluciones","Centro de clasificación regional","Oficina administrativa"],explain:"El Hub es donde los paquetes se organizan y se asignan a los Delivery Partners (DSPs/Flex) para su entrega final al cliente."},
  {cat:"Organización",q:"¿Qué significa DBR?",a:"Daily Business Review",opts:["Daily Business Review","Data Base Report","Delivery Batch Record","Daily Batch Run"],explain:"El DBR es el reporte operativo que se revisa cada mañana. Contiene todas las métricas clave del día anterior y las proyecciones del día actual."},
  {cat:"Organización",q:"¿Qué es un DP (Delivery Partner)?",a:"Socio de entrega (DSP o Flex)",opts:["Socio de entrega (DSP o Flex)","Departamento de planificación","Data Point","Delivery Protocol"],explain:"Los DPs son quienes físicamente entregan los paquetes. Pueden ser DSPs (empresas con flota propia) o conductores Flex (independientes)."},
  {cat:"Organización",q:"¿Qué significa DSP?",a:"Delivery Service Partner",opts:["Delivery Service Partner","Digital Service Platform","Daily Shipment Plan","Dispatch Service Protocol"],explain:"Los DSPs son empresas independientes que contratan conductores y vehículos para entregar paquetes de Amazon. Son el principal canal de entrega."},
  {cat:"Organización",q:"¿Qué región es SEU?",a:"Southern Europe (Europa del Sur)",opts:["Southern Europe (Europa del Sur)","Southeast Union","Spain EU","South East Unit"],explain:"SEU incluye países como España, Italia y Portugal. Es una de las regiones dentro de la estructura EU de Amazon Logistics."},
  {cat:"Organización",q:"¿Qué significa WW HDP?",a:"Worldwide Hub Delivery Program",opts:["Worldwide Hub Delivery Program","Weekly Warehouse Distribution Plan","World Wide High Demand Priority","Warehouse Hub Dispatch Protocol"],explain:"WW HDP es el programa global que gestiona las entregas desde Hubs. Define estándares y métricas a nivel mundial para todas las operaciones Hub."},

  // === CATEGORÍA: SnOP ===
  {cat:"SnOP",q:"¿Qué significa SnOP?",a:"Sales and Operations Planning",opts:["Sales and Operations Planning","Station Network Operations","Supply and Order Processing","Shipment Notification Protocol"],explain:"SnOP es el proceso de planificación que alinea la demanda esperada (ventas) con la capacidad operativa. Define cuántos paquetes se esperan y si hay capacidad para manejarlos."},
  {cat:"SnOP",q:"¿Qué significa OFD?",a:"Out for Delivery (paquetes que salieron a reparto)",opts:["Out for Delivery (paquetes que salieron a reparto)","Order Fulfillment Date","Outbound Freight Dispatch","Overnight Fast Delivery"],explain:"OFD es el momento en que el paquete sale de la estación en la van del conductor. Es la métrica de volumen que realmente está en camino al cliente."},
  {cat:"SnOP",q:"¿Qué es Fcst?",a:"Forecast (Pronóstico de volumen)",opts:["Forecast (Pronóstico de volumen)","Fast count","Fulfillment cost","First class shipment time"],explain:"El Forecast se calcula semanas antes y predice cuántos paquetes llegarán. Se compara con el volumen real para detectar desviaciones y ajustar capacidad."},
  {cat:"SnOP",q:"¿Qué significa D0?",a:"Day Zero (día actual/hoy)",opts:["Day Zero (día actual/hoy)","Delivery Zero defects","Dispatch Order","Default Origin"],explain:"D0 = hoy, D-1 = ayer, D+1 = mañana. Se usa para referirse a métricas del día actual vs. proyecciones futuras."},
  {cat:"SnOP",q:"¿Qué es W0/W1?",a:"Semana actual / Semana siguiente",opts:["Semana actual / Semana siguiente","Warehouse 0 / Warehouse 1","Wave 0 / Wave 1","Worker shift 0 / 1"],explain:"W0 es la semana en curso, W1 la próxima. Se usa para comparar forecast vs. realidad y planificar capacidad con anticipación."},
  {cat:"SnOP",q:"¿Qué mide Cap Utilization?",a:"Porcentaje de uso de la capacidad instalada de una estación",opts:["Porcentaje de uso de la capacidad instalada de una estación","Capacidad de los camiones","Capital utilizado en operaciones","Cantidad de personal activo"],explain:"Si una estación puede procesar 10,000 paquetes y recibe 9,400, su Cap Util es 94%. Arriba de 98% es riesgo de saturación."},
  {cat:"SnOP",q:"¿Qué es New Intake?",a:"Volumen nuevo de paquetes que ingresa a la red logística",opts:["Volumen nuevo de paquetes que ingresa a la red logística","Nuevos empleados contratados","Nuevas rutas creadas","Nuevos DSPs incorporados"],explain:"New Intake es el flujo de paquetes nuevos que entran al sistema. Se compara vs. Forecast para saber si viene más o menos volumen del esperado."},
  {cat:"SnOP",q:"¿Qué significa WtD?",a:"Week to Date (acumulado de la semana)",opts:["Week to Date (acumulado de la semana)","Warehouse to Delivery","Wait time Distribution","Weekly total Dispatched"],explain:"WtD suma todos los datos desde el lunes hasta hoy. Permite ver tendencias semanales sin esperar al cierre de semana."},
  {cat:"SnOP",q:"¿Qué es WON en attainment?",a:"Week Over Network (métrica semanal sobre la red)",opts:["Week Over Network (métrica semanal sobre la red)","Win Over Next","Warehouse Operations Number","Weekly Order Notification"],explain:"WON mide el attainment acumulado de toda la semana a nivel de red completa. Es la vista macro de cuánto volumen AMZL está capturando."},
  {cat:"SnOP",q:"Si Cap Utilization D0 es 94.08%, ¿qué significa?",a:"Las estaciones están usando el 94% de su capacidad hoy",opts:["Las estaciones están usando el 94% de su capacidad hoy","Se entregó el 94% de los paquetes","El 94% del personal asistió","El forecast fue 94% preciso"],explain:"94% es alto pero manejable. El riesgo empieza arriba de 98% donde cualquier pico inesperado puede saturar la estación y generar sidelined shipments."},
  {cat:"SnOP",q:"¿Cuántas estaciones están en riesgo si Cap Util > 98% = 154?",a:"154 estaciones están cerca de saturarse",opts:["154 estaciones están cerca de saturarse","154 paquetes están en riesgo","154 rutas están llenas","154 DSPs están al máximo"],explain:"Estas 154 estaciones necesitan atención inmediata: redirigir volumen, agregar capacidad o hacer sideline preventivo para evitar colapso operativo."},

  // === CATEGORÍA: LMDX ===
  {cat:"LMDX",q:"¿Qué significa LMDX?",a:"Last Mile Delivery Experience",opts:["Last Mile Delivery Experience","Logistics Management Data Exchange","Load Management Dispatch","Last Mile Distribution Index"],explain:"LMDX mide la calidad de la experiencia del cliente en la última milla: ¿llegó a tiempo? ¿primer intento? ¿sin daños? Es la sección de calidad del DBR."},
  {cat:"LMDX",q:"¿Qué es un BPS (Basis Point)?",a:"1 BPS = 0.01%, mide impacto en coste",opts:["1 BPS = 0.01%, mide impacto en coste","Batches Per Second","Business Performance Score","Bulk Package Shipment"],explain:"Si Last Mile = 36 BPS, significa que el coste de última milla representa 0.36% del valor. Se usa porque los cambios son pequeños y los % normales no capturan bien la variación."},
  {cat:"LMDX",q:"¿Qué mide DPMO?",a:"Defectos por millón de oportunidades",opts:["Defectos por millón de oportunidades","Deliveries Per Month","Daily Package Movement Output","Dispatch Priority Management Order"],explain:"DPMO normaliza los defectos para comparar estaciones de diferente tamaño. 385 DPMO = 385 fallos por cada millón de paquetes procesados."},
  {cat:"LMDX",q:"¿Qué es PDD?",a:"Promised Delivery Date (fecha prometida al cliente)",opts:["Promised Delivery Date (fecha prometida al cliente)","Package Delivery Dispatch","Priority Delivery Day","Post-Delivery Data"],explain:"PDD es lo que el cliente ve en su pedido: 'Llega el martes'. Si no se cumple, se pierde attainment por PDD miss y puede generar concesiones."},
  {cat:"LMDX",q:"¿Qué significa DEA en LMDX?",a:"Delivery Execution Attempt (ventana de intento de entrega)",opts:["Delivery Execution Attempt (ventana de intento de entrega)","Daily Efficiency Analysis","Dispatch Error Alert","Delivery Exception Action"],explain:"DEA es la ventana de tiempo asignada para intentar la entrega. Si el conductor intenta dentro de esa ventana, cuenta como 'Attempted in DEA'. Meta: >99%."},
  {cat:"LMDX",q:"¿Qué es NOV?",a:"Not on Van (paquete no cargado en la furgoneta)",opts:["Not on Van (paquete no cargado en la furgoneta)","Network Over Volume","Next Order Verification","No Operational Vehicle"],explain:"NOV ocurre cuando un paquete estaba asignado a una ruta pero no se cargó en la van. Causa: error de escaneo, paquete no encontrado, o sobrecarga."},
  {cat:"LMDX",q:"¿Qué significa OV?",a:"Over Volume (exceso de volumen sobre capacidad)",opts:["Over Volume (exceso de volumen sobre capacidad)","Order Verified","Outbound Vehicle","Operational Variance"],explain:"OV indica que se despacharon más paquetes de los que la ruta podía manejar. Puede causar entregas fallidas o rescates."},
  {cat:"LMDX",q:"¿Qué es PANDA?",a:"Sistema interno que calcula el Attainment",opts:["Sistema interno que calcula el Attainment","Herramienta de tracking de paquetes","Sistema de nómina","App de comunicación interna"],explain:"PANDA determina qué paquetes AMZL puede 'ganar' vs. otros carriers. Calcula numerador (ganados) / denominador (oportunidades totales) = Attainment %."},
  {cat:"LMDX",q:"¿Qué son Slow Connections (SC)?",a:"Conexiones lentas entre nodos de la red",opts:["Conexiones lentas entre nodos de la red","Estaciones pequeñas","Conductores lentos","Sistemas caídos"],explain:"SC son rutas de transporte entre centros que tardan demasiado, haciendo que el paquete no llegue a tiempo a la estación para cumplir el PDD."},
  {cat:"LMDX",q:"¿Qué significa ATS?",a:"Available to Ship (disponible para envío)",opts:["Available to Ship (disponible para envío)","Automated Tracking System","Average Time to Sort","All Time Score"],explain:"ATS es el momento en que un paquete está listo para ser asignado a un carrier. Es el punto donde PANDA decide si AMZL puede 'ganarlo' o no."},
  {cat:"LMDX",q:"Si First Day Delivery Success es 98.81%, ¿qué significa?",a:"El 98.81% de paquetes se entregó en el primer día prometido",opts:["El 98.81% de paquetes se entregó en el primer día prometido","El 98.81% de conductores completó su ruta","El 98.81% de estaciones operó sin problemas","El 98.81% de clientes respondió positivamente"],explain:"Esta es una de las métricas más importantes de calidad. El 1.19% restante son paquetes que no llegaron en su PDD y pueden generar concesiones."},
  {cat:"LMDX",q:"¿Qué mide Concession DPMO?",a:"Compensaciones al cliente por fallo, en defectos por millón",opts:["Compensaciones al cliente por fallo, en defectos por millón","Concesiones de espacio en almacén","Descuentos a DSPs","Permisos de estacionamiento"],explain:"Cada concesión es dinero que Amazon devuelve al cliente por un fallo. 6,959 DPMO = ~7 concesiones por cada 1,000 paquetes. Impacta directamente en P&L."},
  {cat:"LMDX",q:"¿Qué son Conceded Units AMZL Hub?",a:"Unidades con concesión (compensación) otorgada al cliente por fallo",opts:["Unidades con concesión (compensación) otorgada al cliente por fallo","Unidades cedidas a otro carrier","Paquetes transferidos entre hubs","Unidades devueltas al vendedor"],explain:"Son los paquetes reales (no ratio) donde se compensó al cliente. Si son 792, significa 792 reembolsos o reemplazos ese día."},
  {cat:"LMDX",q:"¿Qué mide Lost DPMO - Hub?",a:"Paquetes perdidos por millón de oportunidades en el Hub",opts:["Paquetes perdidos por millón de oportunidades en el Hub","Dinero perdido por millón","Tiempo perdido por operación","Conductores perdidos por mes"],explain:"Paquetes que se perdieron físicamente en el proceso. 342 DPMO es bajo pero cada paquete perdido = concesión + mala experiencia del cliente."},
  {cat:"LMDX",q:"Si Lost DPMO Hub = 342, ¿es grave?",a:"342 paquetes perdidos por millón - relativamente bajo pero se monitorea",opts:["342 paquetes perdidos por millón - relativamente bajo pero se monitorea","Es crítico, hay que cerrar el hub","Es normal, no requiere acción","No se puede evaluar sin contexto"],explain:"342 DPMO equivale a ~0.03% de pérdida. Es bajo, pero en volúmenes de 184K paquetes/día, son ~63 paquetes perdidos diarios que generan concesiones."},
  {cat:"LMDX",q:"¿Qué es Last Mile (bps) [Int PDD - DS] Hub DP?",a:"Coste de última milla en BPS para entregas con PDD internacional",opts:["Coste de última milla en BPS para entregas con PDD internacional","Puntos base de la primera milla","Coste del linehaul internacional","Benchmark de entregas domésticas"],explain:"Mide el coste extra de entregar paquetes con fecha prometida internacional. 84 BPS vs 36 BPS doméstico = las internacionales cuestan 2.3x más en última milla."},
  {cat:"LMDX",q:"Si Last Mile bps Int PDD = 84 vs. Last Mile bps Hub = 36, ¿qué indica?",a:"Las entregas internacionales cuestan más del doble en última milla",opts:["Las entregas internacionales cuestan más del doble en última milla","Hay un error en los datos","El hub internacional es más eficiente","Son métricas no comparables"],explain:"El PDD internacional requiere entregas más rápidas o con ventanas más ajustadas, lo que incrementa el coste. Es un área de oportunidad para optimizar."},

  // === CATEGORÍA: Seguridad ===
  {cat:"Seguridad",q:"¿Qué significa XSI?",a:"Community Member Serious Incident",opts:["Community Member Serious Incident","Extra Safety Inspection","External Security Issue","Cross-Station Incident"],explain:"XSI son incidentes graves que afectan a personas de la comunidad (peatones, ciclistas, etc.) durante las operaciones de entrega. Son los más críticos en seguridad."},
  {cat:"Seguridad",q:"¿Qué es GSOC?",a:"Global Security Operations Center",opts:["Global Security Operations Center","General Station Operations Control","Ground Safety Operations Check","Global Shipment Order Center"],explain:"GSOC monitorea 24/7 todos los eventos de seguridad a nivel global: robos, accidentes, amenazas, emergencias. Reportan directamente en el DBR."},
  {cat:"Seguridad",q:"¿Qué significa OTR en seguridad?",a:"On The Road (incidentes vehiculares en ruta)",opts:["On The Road (incidentes vehiculares en ruta)","Over Time Report","Order Tracking Record","Outbound Transit Route"],explain:"OTR cubre todos los incidentes con vehículos durante la entrega: choques, daños a propiedad, infracciones graves. Se trackea por DSP y por estación."},

  // === CATEGORÍA: Attainment ===
  {cat:"Attainment",q:"¿Qué es Attainment?",a:"% de paquetes que AMZL 'gana' para entregar vs. oportunidades ofrecidas",opts:["% de paquetes que AMZL 'gana' para entregar vs. oportunidades ofrecidas","% de paquetes entregados a tiempo","% de capacidad utilizada","% de conductores activos"],explain:"Attainment = Numerador/Denominador en PANDA. Si hay 100 paquetes disponibles y AMZL puede entregar 85, el attainment es 85%. Es LA métrica del SnOP."},
  {cat:"Attainment",q:"¿Cuáles son las 4 razones de pérdida de Attainment?",a:"Caps, Not feasible, PDD miss, More expensive",opts:["Caps, Not feasible, PDD miss, More expensive","Clima, Tráfico, Personal, Vehículos","Volumen, Calidad, Seguridad, Costo","DSP, Flex, Walker, Milkrun"],explain:"Caps (sin espacio), Not feasible (no llegamos ahí), PDD miss (no a tiempo), More expensive (otro carrier es más barato). Cada una tiene su % de pérdida en el DBR."},
  {cat:"Attainment",q:"¿Qué significa 'Attainment Loss: Caps'?",a:"Pérdida porque la estación alcanzó su límite de capacidad",opts:["Pérdida porque la estación alcanzó su límite de capacidad","Pérdida por capital insuficiente","Pérdida por falta de gorras de uniforme","Pérdida por capacitación insuficiente"],explain:"Si una estación está al 100% de capacidad, PANDA no le asigna más paquetes → se pierden oportunidades. Solución: expandir capacidad o redirigir volumen."},
  {cat:"Attainment",q:"¿Qué significa 'Attainment Loss: PDD miss'?",a:"Pérdida por no poder cumplir la fecha de entrega prometida",opts:["Pérdida por no poder cumplir la fecha de entrega prometida","Pérdida por paquetes dañados","Pérdida por personal ausente","Pérdida por problemas de sistema"],explain:"Si el paquete no puede llegar a la estación a tiempo para cumplir el PDD del cliente, PANDA lo asigna a otro carrier. Causa: slow connections o linehaul tardío."},
  {cat:"Attainment",q:"¿Qué significa 'Attainment Loss: More expensive'?",a:"AMZL resulta más caro que otra opción de envío",opts:["AMZL resulta más caro que otra opción de envío","El paquete es muy costoso","El DSP cobra de más","La ruta es muy larga"],explain:"Amazon compara el CPS de AMZL vs. otros carriers. Si otro es más barato para esa entrega, el paquete se va con ellos. Reducir CPS = ganar más attainment."},
  {cat:"Attainment",q:"¿Qué significa 'Attainment Loss: Not feasible'?",a:"No es factible la entrega por cobertura geográfica",opts:["No es factible la entrega por cobertura geográfica","No hay personal disponible","No hay vehículos","No hay sistema funcionando"],explain:"Zonas donde AMZL no tiene estación cercana o no cubre esa área. Solución a largo plazo: expandir la red con nuevas estaciones."},
  {cat:"Attainment",q:"Si Attainment EU Hub DP = 77.01%, ¿qué significa?",a:"AMZL ganó el 77% de las oportunidades de entrega en EU Hub DP",opts:["AMZL ganó el 77% de las oportunidades de entrega en EU Hub DP","Se entregó el 77% de paquetes","El 77% de estaciones está activo","El 77% del forecast se cumplió"],explain:"De cada 100 paquetes que podrían ir por Hub DP, AMZL captura 77. El 23% restante se pierde por Caps (9.89%), PDD miss (6.69%), Cost (2.54%) y Not feasible (1.73%)."},
  {cat:"Attainment",q:"¿Qué es el numerador (Num) en PANDA?",a:"Paquetes que AMZL ganó para entregar",opts:["Paquetes que AMZL ganó para entregar","Total de paquetes en la red","Paquetes entregados exitosamente","Paquetes devueltos"],explain:"El Num son los paquetes que PANDA asignó a AMZL porque cumplía todos los criterios: capacidad, cobertura, tiempo y coste. Ejemplo real: 47,285 paquetes."},
  {cat:"Attainment",q:"¿Qué es el denominador (Den) en PANDA?",a:"Total de oportunidades ofrecidas a AMZL",opts:["Total de oportunidades ofrecidas a AMZL","Total de paquetes entregados","Total de estaciones activas","Total de conductores disponibles"],explain:"El Den es el total de paquetes que PODRÍAN haber ido por AMZL. Attainment = Num/Den. Ejemplo: 47,285/61,398 = 77.01%."},
  {cat:"Attainment",q:"¿Qué mide Attainment - Caps Losses % WtD?",a:"% acumulado semanal de oportunidades perdidas por límite de capacidad",opts:["% acumulado semanal de oportunidades perdidas por límite de capacidad","% de estaciones con caps","% de paquetes dañados","% de rutas canceladas"],explain:"WtD acumula desde el lunes. Si Caps Loss WtD = 5.75%, significa que en toda la semana, el 5.75% del denominador se perdió por capacidad insuficiente."},
  {cat:"Attainment",q:"Si Caps Losses WtD = 5.75%, ¿qué significa?",a:"En la semana, el 5.75% de oportunidades se perdió por falta de capacidad",opts:["En la semana, el 5.75% de oportunidades se perdió por falta de capacidad","El 5.75% de estaciones cerró","El 5.75% de paquetes se dañó","El 5.75% de conductores faltó"],explain:"Con un denominador de ~46M paquetes semanales, 5.75% = ~2.6M paquetes que no pudimos aceptar. Es la mayor causa de pérdida de attainment."},
  {cat:"Attainment",q:"¿Qué mide Attainment - Slow Connections % WtD?",a:"% semanal de pérdida por conexiones lentas entre nodos de la red",opts:["% semanal de pérdida por conexiones lentas entre nodos de la red","% de internet lento en estaciones","% de conductores lentos","% de sistemas caídos"],explain:"Slow Connections = el transporte entre centros tarda demasiado. 1.34% WtD = ~617K paquetes que no llegaron a tiempo a la estación para cumplir PDD."},
  {cat:"Attainment",q:"¿Qué mide Attainment - Cost Losses % WtD?",a:"% semanal de oportunidades perdidas porque AMZL era más caro",opts:["% semanal de oportunidades perdidas porque AMZL era más caro","% del presupuesto gastado","% de sobrecostes operativos","% de multas pagadas"],explain:"1.05% WtD = ~483K paquetes donde otro carrier era más barato. Reducir el CPS del Hub es clave para recuperar este volumen."},
  {cat:"Attainment",q:"Si Losses due to Caps = 525,846, ¿qué representa?",a:"Paquetes que no se pudieron aceptar por falta de capacidad en estaciones",opts:["Paquetes que no se pudieron aceptar por falta de capacidad en estaciones","Dinero perdido en dólares","Minutos perdidos","Conductores sin ruta"],explain:"525,846 paquetes en un solo día que AMZL no pudo tomar porque las estaciones estaban llenas. Es volumen que se fue a otros carriers."},
  {cat:"Attainment",q:"¿Qué es CO - Roster Compliance W0/W1?",a:"Cumplimiento del roster de DSPs en semana actual (W0) y siguiente (W1)",opts:["Cumplimiento del roster de DSPs en semana actual (W0) y siguiente (W1)","Compliance Officer semanal","Control de calidad semanal","Conteo de operaciones"],explain:"Mide si los DSPs confirman y cumplen las rutas/turnos asignados. Si no cumplen, hay menos capacidad real disponible → más pérdida por Caps."},

  // === CATEGORÍA: Operaciones ===
  {cat:"Operaciones",q:"¿Qué es un Milkrun?",a:"Ruta de recogida/entrega multi-parada entre estaciones",opts:["Ruta de recogida/entrega multi-parada entre estaciones","Ruta de entrega de lácteos","Turno nocturno","Ruta express premium"],explain:"Como el lechero que para en cada casa, un Milkrun recoge/entrega paquetes en múltiples puntos. Es más eficiente en coste y emisiones que rutas individuales."},
  {cat:"Operaciones",q:"¿Qué es Linehaul?",a:"Transporte de larga distancia entre centros logísticos",opts:["Transporte de larga distancia entre centros logísticos","Última milla de entrega","Línea de producción en almacén","Ruta de un solo conductor"],explain:"Linehaul = camiones grandes que mueven paquetes entre Sortation Centers y Hubs. Si un linehaul se retrasa, genera Volume at Risk y posible PDD miss."},
  {cat:"Operaciones",q:"¿Qué es Last Mile?",a:"Último tramo de entrega desde la estación hasta la puerta del cliente",opts:["Último tramo de entrega desde la estación hasta la puerta del cliente","Última milla del linehaul","Último turno del día","Última revisión de calidad"],explain:"Last Mile es donde ocurre la magia: el paquete sale del Hub en una van y llega al cliente. Es el tramo más caro por paquete pero el más visible para el cliente."},
  {cat:"Operaciones",q:"¿Qué es Rescue/Rescued Volume?",a:"Volumen reasignado a otro conductor cuando uno no puede completar su ruta",opts:["Volumen reasignado a otro conductor cuando uno no puede completar su ruta","Paquetes rescatados de daño","Volumen recuperado de devoluciones","Paquetes encontrados perdidos"],explain:"Si un conductor tiene 150 paquetes y solo puede entregar 120, los 30 restantes se 'rescatan' enviando otro conductor. Genera coste extra pero salva entregas."},
  {cat:"Operaciones",q:"¿Qué son Sidelined Shipments?",a:"Paquetes retirados del flujo normal que no se entregarán ese día",opts:["Paquetes retirados del flujo normal que no se entregarán ese día","Paquetes en la línea lateral del almacén","Envíos secundarios","Paquetes de baja prioridad"],explain:"Sideline = sacar paquetes del flujo porque no se pueden entregar hoy (llegaron tarde, sin capacidad, etc.). Se reintentan al día siguiente → generan Ageing."},
  {cat:"Operaciones",q:"¿Qué es Roster Compliance?",a:"Mide si los DSPs cumplen con el planning de turnos y rutas asignadas",opts:["Mide si los DSPs cumplen con el planning de turnos y rutas asignadas","Cumplimiento de uniformes","Lista de asistencia diaria","Registro de vehículos"],explain:"Si un DSP confirma 10 rutas pero solo presenta 8 conductores, su Roster Compliance baja. Esto reduce la capacidad real y puede causar pérdida de attainment por Caps."},
  {cat:"Operaciones",q:"¿Qué identifica un código como EHM5?",a:"Una estación específica dentro de la jerarquía de red",opts:["Una estación específica dentro de la jerarquía de red","Un tipo de paquete","Un código de error","Un turno de trabajo"],explain:"Cada estación tiene un código único (ej: EHM5). La E = Europa, las letras/números identifican la ubicación. Se usa en todos los reportes para referirse a estaciones específicas."},
  {cat:"Operaciones",q:"¿Cuál es la jerarquía de una estación en ES?",a:"EU > SEU > ES > WW HDP > WW HDP ES > Estación",opts:["EU > SEU > ES > WW HDP > WW HDP ES > Estación","País > Ciudad > Calle","Global > Local","AMZL > DSP > Conductor"],explain:"La jerarquía permite agregar datos a diferentes niveles: puedes ver métricas de una estación, de España, de Europa del Sur, o de toda EU."},

  // === CATEGORÍA: Finance ===
  {cat:"Finance",q:"¿Qué significa CPS en Finance?",a:"Cost Per Shipment (coste por paquete enviado)",opts:["Cost Per Shipment (coste por paquete enviado)","Capacity Planning System","Central Processing Station","Customer Priority Score"],explain:"CPS es EL número de Finance. Total CPS = cuánto cuesta entregar cada paquete. Se descompone en: Store CPS + Milkrun CPS + Fixed CPS."},
  {cat:"Finance",q:"¿Qué es HubDP Store Cost?",a:"Coste total de operación del Hub para entregas con Delivery Partners",opts:["Coste total de operación del Hub para entregas con Delivery Partners","Coste de almacenamiento","Precio de venta de productos","Coste de alquiler del edificio"],explain:"Incluye todo lo que cuesta operar el Hub para despachar con DPs: personal de estación, equipos, tecnología, etc. Se divide entre paquetes para obtener el CPS."},
  {cat:"Finance",q:"¿Qué mide Hub Store CPS - HubDP?",a:"Coste por paquete de la operación del Hub con DPs",opts:["Coste por paquete de la operación del Hub con DPs","Capacidad por estación","Clientes por segmento","Conductores por shift"],explain:"Si Store Cost = $181,574 y se despacharon 181,574 paquetes, el Store CPS = ~$1.00. Es el componente más grande del Total CPS."},
  {cat:"Finance",q:"¿Qué es Milkrun CPS?",a:"Coste por paquete de las rutas milkrun",opts:["Coste por paquete de las rutas milkrun","Cantidad de milkruns por semana","Capacidad máxima de un milkrun","Coste del vehículo milkrun"],explain:"Los milkruns tienen un CPS separado ($0.55) porque su modelo de coste es diferente: una ruta entrega muchos paquetes en múltiples paradas."},
  {cat:"Finance",q:"¿Qué incluye Other Fixed & Overhead CPS?",a:"Costes fijos y generales por paquete (alquiler, admin, etc.)",opts:["Costes fijos y generales por paquete (alquiler, admin, etc.)","Costes de horas extra","Costes de paquetes dañados","Costes de devoluciones"],explain:"Son costes que no varían con el volumen: alquiler del edificio, managers, sistemas IT, etc. Se reparten entre todos los paquetes. Ejemplo: $0.10 por paquete."},
  {cat:"Finance",q:"¿Qué es Total CPS - HubDP?",a:"Suma de todos los costes por paquete (Store + Milkrun + Fixed)",opts:["Suma de todos los costes por paquete (Store + Milkrun + Fixed)","Total de paquetes enviados","Total de conductores activos","Total de estaciones operativas"],explain:"Total CPS = $0.92 (Store) + $0.55 (Milkrun) + $0.10 (Fixed) = $1.56. Este número se compara contra el Benchmark para saber si somos eficientes."},
  {cat:"Finance",q:"¿Qué es Benchmark CPS - Urban?",a:"Coste de referencia por paquete en zonas urbanas para comparar",opts:["Coste de referencia por paquete en zonas urbanas para comparar","Mejor CPS histórico","CPS del competidor","CPS objetivo del año"],explain:"El Benchmark ($2.25) es lo que costaría entregar ese paquete por otro método. Si nuestro CPS ($1.56) es menor, el Hub está generando valor."},
  {cat:"Finance",q:"¿Qué indica Delta vs Benchmark CPS?",a:"Diferencia entre el CPS real del Hub y el benchmark urbano",opts:["Diferencia entre el CPS real del Hub y el benchmark urbano","Variación del volumen","Cambio en el número de rutas","Diferencia de personal"],explain:"Delta = Benchmark - CPS real. Si es positivo ($0.69), estamos ahorrando. Si fuera negativo, el Hub sería más caro que la alternativa."},
  {cat:"Finance",q:"Si Delta vs Benchmark CPS es positivo (ej: 0.69), ¿qué significa?",a:"El Hub es más barato que el benchmark (ahorra $0.69 por paquete)",opts:["El Hub es más barato que el benchmark (ahorra $0.69 por paquete)","El Hub es más caro que el benchmark","Hay un error en el cálculo","El volumen subió 0.69%"],explain:"$0.69 de ahorro × 181,574 paquetes = ~$125K de ahorro en un solo día. Esto justifica la existencia del Hub vs. usar carriers externos."},
  {cat:"Finance",q:"¿Qué es Delta vs Benchmark Costs (SL)?",a:"Ahorro total en dólares vs. benchmark a nivel de Service Level",opts:["Ahorro total en dólares vs. benchmark a nivel de Service Level","Coste de penalización","Presupuesto restante","Inversión en nuevas estaciones"],explain:"Es el Delta CPS multiplicado por el volumen total. Ejemplo: $0.69 × volumen = $129,490.97 de ahorro total. Es lo que presentas a Finance como valor generado."},
  {cat:"Finance",q:"Si Total CPS = $1.56 y Benchmark = $2.25, ¿el Hub es eficiente?",a:"Sí, el Hub cuesta $0.69 menos por paquete que el benchmark",opts:["Sí, el Hub cuesta $0.69 menos por paquete que el benchmark","No, debería ser $0","No se puede determinar","Solo si el volumen es alto"],explain:"El Hub ahorra 31% vs. el benchmark. Esto es excelente. El objetivo es mantener o mejorar este delta mientras se crece en volumen."},

  // === CATEGORÍA: ACES Station ===
  {cat:"ACES Station",q:"¿Qué son Ageing Shipments?",a:"Paquetes atascados en la estación que no se han entregado en X días",opts:["Paquetes atascados en la estación que no se han entregado en X días","Paquetes antiguos del inventario","Paquetes con fecha de caducidad","Envíos de clientes mayores"],explain:"Cada día que un paquete no se entrega, 'envejece'. Se mide en tramos: 3, 4, 5, 6+ días. Los de 6+ son críticos y probablemente generarán concesión."},
  {cat:"ACES Station",q:"¿Por qué se miden Ageing Shipments en tramos (3, 4, 5, 6+ días)?",a:"Para identificar la gravedad: más días = más urgente resolver",opts:["Para identificar la gravedad: más días = más urgente resolver","Por requisito legal","Para calcular el coste de almacenamiento","Para asignar prioridad de entrega"],explain:"3 días = atención. 4 días = acción. 5 días = escalación. 6+ días = crítico, probablemente ya se generó concesión y el cliente está insatisfecho."},
  {cat:"ACES Station",q:"Si Ageing 6+ Days = 8,435, ¿qué indica?",a:"8,435 paquetes llevan más de 6 días sin entregarse (crítico)",opts:["8,435 paquetes llevan más de 6 días sin entregarse (crítico)","8,435 paquetes se entregaron hace 6 días","8,435 estaciones tienen 6+ días de operación","8,435 conductores llevan 6+ días trabajando"],explain:"8,435 paquetes con 6+ días son una emergencia operativa. Cada uno probablemente ya generó una concesión. Se necesita RCA y plan de acción inmediato."},
  {cat:"ACES Station",q:"¿Qué significa FPY DPMO (WW Scorecard)?",a:"First Pass Yield - defectos de calidad al primer intento, por millón",opts:["First Pass Yield - defectos de calidad al primer intento, por millón","Full Package Yield","Final Processing Year","Freight Priority Yield"],explain:"FPY mide cuántos paquetes se procesan correctamente al primer intento sin errores. 1,483 DPMO = 1,483 errores por millón de paquetes procesados en estación."},
  {cat:"ACES Station",q:"¿Qué mide On Time Dispatch % - DSP?",a:"% de rutas DSP que salieron a tiempo de la estación",opts:["% de rutas DSP que salieron a tiempo de la estación","% de paquetes entregados a tiempo","% de conductores puntuales","% de camiones que llegaron a tiempo"],explain:"Si las rutas salen tarde, los conductores tienen menos tiempo para entregar → más rescates, más fallos de DEA. 98.13% es bueno pero el 1.87% tardío impacta."},
  {cat:"ACES Station",q:"Si On Time Dispatch = 98.13%, ¿qué significa?",a:"El 98.13% de las rutas DSP salieron de la estación en horario",opts:["El 98.13% de las rutas DSP salieron de la estación en horario","El 98.13% de paquetes se entregó","El 98.13% de personal asistió","El 98.13% de capacidad se usó"],explain:"De 46,936 rutas, 46,056 salieron a tiempo. Las 880 tardías pueden afectar miles de paquetes en entregas fuera de ventana DEA."},
  {cat:"ACES Station",q:"¿Qué es ASL Utilisation %?",a:"Available Shift Labor - % de uso del personal disponible por turno",opts:["Available Shift Labor - % de uso del personal disponible por turno","Average Station Load","Automated Sort Line utilization","Assigned Shipment Level"],explain:"78% ASL = usamos el 78% del personal disponible. Hay un 22% de margen. Si sube mucho (>95%), no hay buffer para picos inesperados."},
  {cat:"ACES Station",q:"¿Qué es ADTA Utilisation %?",a:"Available Delivery Time Allocation - % uso del tiempo de entrega disponible",opts:["Available Delivery Time Allocation - % uso del tiempo de entrega disponible","Average Daily Transport Activity","Automated Dispatch Time Analysis","Annual Delivery Target Achievement"],explain:"ADTA mide si las rutas usan todo el tiempo asignado. 100.30% = se está usando ligeramente más tiempo del planificado, señal de rutas sobrecargadas."},
  {cat:"ACES Station",q:"Si ADTA Utilisation = 100.30%, ¿qué indica?",a:"Se está usando más tiempo del asignado (sobrecarga ligera)",opts:["Se está usando más tiempo del asignado (sobrecarga ligera)","Todo funciona perfectamente","Hay un 0.30% de error","Sobran recursos de tiempo"],explain:"100.30% significa que los conductores tardan un poco más de lo planificado. Puede indicar rutas con demasiados paquetes o zonas difíciles de entregar."},
  {cat:"ACES Station",q:"Si ASL Utilisation = 78.05%, ¿es bueno o malo?",a:"Hay margen: solo se usa el 78% del personal disponible",opts:["Hay margen: solo se usa el 78% del personal disponible","Es malo, debería ser 100%","Es excelente, sobra personal","No se puede determinar sin más contexto"],explain:"78% es saludable. Deja buffer para picos. Si fuera 95%+ no habría margen para absorber volumen extra. Si fuera 50%, estaríamos pagando personal ocioso."},

  // === CATEGORÍA: ACES Road ===
  {cat:"ACES Road",q:"¿Qué mide Carbon Emission Reduction vs Van?",a:"Reducción de emisiones CO2 al usar métodos alternativos vs. furgoneta",opts:["Reducción de emisiones CO2 al usar métodos alternativos vs. furgoneta","Consumo de combustible por van","Número de vans eléctricas","Coste del carbono por ruta"],explain:"Mide el impacto ambiental positivo de usar walkers, bicicletas o vehículos eléctricos en lugar de furgonetas diésel. Es parte de los objetivos de sostenibilidad de Amazon."},
  {cat:"ACES Road",q:"¿Qué mide Delivered by Milkrun %?",a:"% de paquetes entregados mediante rutas milkrun vs. total",opts:["% de paquetes entregados mediante rutas milkrun vs. total","% de milkruns completados","% de leche entregada","% de rutas multi-parada"],explain:"Indica la adopción del modelo milkrun. 1.88% es bajo → hay oportunidad de crecer este canal que es más eficiente en coste (CPS $0.55 vs $0.92 del Hub normal)."},
  {cat:"ACES Road",q:"Si Delivered by Milkrun = 1.88%, ¿qué indica?",a:"Solo el 1.88% del volumen se entrega por milkrun (adopción baja)",opts:["Solo el 1.88% del volumen se entrega por milkrun (adopción baja)","El 1.88% de milkruns falló","Se ahorra 1.88% en costes","1.88% de conductores usan milkrun"],explain:"De 184,501 paquetes entregados, solo 3,464 fueron por milkrun. Hay potencial de crecimiento enorme si se expanden las rutas milkrun."},
  {cat:"ACES Road",q:"¿Qué es SPR (Milkrun SPR)?",a:"Shipments Per Route - paquetes entregados por cada ruta milkrun",opts:["Shipments Per Route - paquetes entregados por cada ruta milkrun","Speed Per Route","Station Performance Rating","Standard Processing Rate"],explain:"SPR mide la eficiencia de cada ruta milkrun. 403 paquetes por ruta es muy alto comparado con rutas DSP normales (~150-200), lo que explica el bajo CPS."},
  {cat:"ACES Road",q:"Si Milkrun SPR = 403.65, ¿qué significa?",a:"Cada ruta milkrun entrega en promedio 403 paquetes (alta eficiencia)",opts:["Cada ruta milkrun entrega en promedio 403 paquetes (alta eficiencia)","403 milkruns activos","403 minutos por ruta","403 km por ruta"],explain:"403 paquetes/ruta vs ~150 de una ruta DSP normal. Los milkruns son 2-3x más eficientes porque entregan en puntos de alta densidad (lockers, hubs urbanos)."},
  {cat:"ACES Road",q:"¿Qué mide Average Daily Volume Per Hub?",a:"Promedio de paquetes procesados por hub al día",opts:["Promedio de paquetes procesados por hub al día","Promedio de conductores por hub","Promedio de horas operativas","Promedio de rutas por hub"],explain:"Permite comparar hubs entre sí y detectar desbalances. Si un hub procesa mucho más que el promedio, puede estar sobrecargado."},
  {cat:"ACES Road",q:"¿Qué es Total Number of Milkruns (Harmony)?",a:"Cantidad total de rutas milkrun activas según el sistema Harmony",opts:["Cantidad total de rutas milkrun activas según el sistema Harmony","Milkruns históricos totales","Milkruns cancelados","Milkruns planificados para el futuro"],explain:"Harmony es el sistema que gestiona las rutas milkrun. Este número muestra cuántas rutas están operativas hoy en toda la red."},

  // === CATEGORÍA: WFS ===
  {cat:"WFS",q:"¿Qué es D1S (Day One Starts)?",a:"Número de nuevos empleados que empiezan su primer día de trabajo",opts:["Número de nuevos empleados que empiezan su primer día de trabajo","Día 1 de una estación nueva","Primer envío del día","Primera ruta despachada"],explain:"D1S es el pipeline de contratación hecho realidad. Si pediste 61 personas (LO) y empezaron 62 (D1S), tu Fill Rate es 101.64%. Más D1S = más capacidad futura."},
  {cat:"WFS",q:"Si Weekly D1S = 62, ¿qué significa?",a:"62 personas comenzaron a trabajar esta semana",opts:["62 personas comenzaron a trabajar esta semana","62 rutas nuevas creadas","62 estaciones abiertas","62 DSPs contratados"],explain:"62 nuevos associates que empezaron. Necesitan onboarding y ramp-up antes de ser 100% productivos. El WtD (568) muestra el acumulado de la semana."},
  {cat:"WFS",q:"¿Qué es Locked Labor Order (LO)?",a:"Pedido de personal confirmado/bloqueado sin cambios de último momento",opts:["Pedido de personal confirmado/bloqueado sin cambios de último momento","Orden de bloqueo de estación","Pedido de candados para lockers","Orden laboral legal"],explain:"LO es el pedido 'oficial' de personal que se hizo con anticipación. Se 'bloquea' para que WFS pueda reclutar contra ese número. Ejemplo: 61 personas pedidas."},
  {cat:"WFS",q:"¿Qué significa RLC (Red Level Changes)?",a:"Cambios de último momento en los pedidos de personal (urgentes)",opts:["Cambios de último momento en los pedidos de personal (urgentes)","Reducciones de nivel de capacidad","Reportes de nivel crítico","Rotación laboral controlada"],explain:"RLC son ajustes de emergencia: 'necesitamos 17 personas más esta semana'. Son difíciles de cubrir porque no hubo tiempo de reclutar. LO+RLC = necesidad real total."},
  {cat:"WFS",q:"¿Qué es Labor Order incl. Red Level Changes?",a:"Pedido total de personal incluyendo ajustes urgentes de última hora",opts:["Pedido total de personal incluyendo ajustes urgentes de última hora","Orden de trabajo con nivel rojo de riesgo","Personal en alerta roja","Pedido cancelado por emergencia"],explain:"LO (61) + RLC (17) = 78 personas necesarias en total. El Fill Rate vs este número (79.49%) es más bajo porque los RLC son difíciles de cubrir a tiempo."},
  {cat:"WFS",q:"¿Qué mide New Hire Fill Rate (vs Locked LO)?",a:"% de posiciones cubiertas vs. las que se pidieron originalmente",opts:["% de posiciones cubiertas vs. las que se pidieron originalmente","% de formularios completados","% de capacitación terminada","% de uniformes entregados"],explain:"Fill Rate = D1S / LO × 100. Si pediste 61 y empezaron 62, tu Fill Rate = 101.64%. Arriba de 100% = cubriste más de lo pedido originalmente."},
  {cat:"WFS",q:"Si Fill Rate vs Locked LO = 101.64%, ¿qué indica?",a:"Se contrató más gente de la pedida originalmente (101% cubierto)",opts:["Se contrató más gente de la pedida originalmente (101% cubierto)","Hay un error en el sistema","Sobra un 1.64% de personal","El 1.64% renunció"],explain:"Excelente resultado vs. el plan original. Pero vs. LO+RLC (78 necesarias), solo se cubrió 79.49% → faltan 16 personas para cubrir la necesidad real."},
  {cat:"WFS",q:"Si Fill Rate vs LO+RLC = 79.49%, ¿qué indica?",a:"Solo se cubrió el 79% del personal total necesario (incluyendo urgentes)",opts:["Solo se cubrió el 79% del personal total necesario (incluyendo urgentes)","El 79% del personal es nuevo","El 79% completó su turno","El 79% pasó la capacitación"],explain:"Faltan ~16 personas de las 78 necesarias. Esto puede traducirse en menos capacidad operativa → más Caps loss → menos attainment. Requiere acción."},
  {cat:"WFS",q:"¿Por qué hay dos Fill Rates (vs LO y vs LO+RLC)?",a:"Uno mide contra el plan original, otro contra el plan + cambios urgentes",opts:["Uno mide contra el plan original, otro contra el plan + cambios urgentes","Uno es semanal y otro mensual","Uno es de DSPs y otro de Flex","Uno es de día y otro de noche"],explain:"vs LO = ¿cumplimos el plan? (sí, 101%). vs LO+RLC = ¿tenemos la gente que realmente necesitamos? (no, solo 79%). El segundo es la realidad operativa."},

  // === CATEGORÍA: Volume at Risk ===
  {cat:"Volume at Risk",q:"¿Qué es Volume at Risk - Linehaul?",a:"Volumen en riesgo por problemas de transporte de larga distancia",opts:["Volumen en riesgo por problemas de transporte de larga distancia","Volumen en camiones grandes","Paquetes pesados","Envíos internacionales"],explain:"51,839 paquetes que pueden no llegar a tiempo porque el camión de linehaul tuvo problemas: retraso, avería, accidente, o congestión en ruta."},
  {cat:"Volume at Risk",q:"¿Qué es Volume at Risk - Ops Issue?",a:"Volumen en riesgo por problemas operativos",opts:["Volumen en riesgo por problemas operativos","Volumen de operaciones especiales","Paquetes de gran tamaño","Envíos con seguro"],explain:"5,859 paquetes en riesgo por problemas dentro de la estación: falta de personal, equipos averiados, errores de proceso, etc."},
  {cat:"Volume at Risk",q:"¿Qué es Volume To Be Rescued?",a:"Volumen que necesita ser reasignado/rescatado",opts:["Volumen que necesita ser reasignado/rescatado","Paquetes dañados por recuperar","Volumen de emergencia","Envíos perdidos"],explain:"35,786 paquetes que conductores no pudieron entregar y necesitan otro conductor. Cada rescate tiene coste extra pero salva la entrega del día."},
  {cat:"Volume at Risk",q:"¿Qué diferencia hay entre Sidelined Shipments y Sideline Out Actuals?",a:"Sidelined = planificados a retirar, Sideline Out Actuals = realmente retirados",opts:["Sidelined = planificados a retirar, Sideline Out Actuals = realmente retirados","Son lo mismo con diferente nombre","Uno es de entrada y otro de salida","Uno es manual y otro automático"],explain:"Sidelined (44,633) es la proyección. Sideline Out Actuals (46,834) es lo que realmente pasó. La diferencia (2,201) son paquetes extra que se tuvieron que retirar."},
  {cat:"Volume at Risk",q:"Si Sidelined = 44,633 pero Sideline Out = 46,834, ¿qué pasó?",a:"Se retiraron más paquetes de los planificados (2,201 extra)",opts:["Se retiraron más paquetes de los planificados (2,201 extra)","Hay un error de conteo","Se recuperaron paquetes","Los números son normales"],explain:"2,201 paquetes extra se tuvieron que retirar del flujo. Puede indicar problemas no previstos: linehaul tardío, ausentismo de conductores, o picos de volumen."},

  // === CATEGORÍA: Métricas ===
  {cat:"Métricas",q:"Si Delivered Shipments Hub DP = 184,499, ¿qué representa?",a:"Paquetes entregados por socios de entrega del Hub",opts:["Paquetes entregados por socios de entrega del Hub","Ingresos del día","Kilómetros recorridos","Horas trabajadas"],explain:"184,499 paquetes que llegaron a manos del cliente ese día a través de DSPs y Flex que operan desde el Hub. Es el output principal de la operación."},
  {cat:"Métricas",q:"Si Attainment WON = 85.86%, ¿es bueno o malo?",a:"Es el % que AMZL ganó de oportunidades en la semana sobre la red",opts:["Es el % que AMZL ganó de oportunidades en la semana sobre la red","Es malo, debería ser 100%","Es el porcentaje de paquetes dañados","Es la tasa de ausentismo"],explain:"85.86% WON significa que de todo el volumen disponible en la red esta semana, AMZL capturó el 85.86%. El 14.14% restante se fue a otros carriers por Caps, PDD, Cost o Feasibility."},
  {cat:"Métricas",q:"Si Positive Response Rate = 88.85%, ¿qué mide?",a:"Tasa de respuesta positiva del cliente sobre su experiencia",opts:["Tasa de respuesta positiva del cliente sobre su experiencia","% de conductores satisfechos","% de DSPs que respondieron encuesta","% de estaciones con buen clima laboral"],explain:"De 1,534 clientes que respondieron la encuesta post-entrega, 1,363 (88.85%) dieron feedback positivo. Es la voz directa del cliente sobre nuestro servicio."},
  {cat:"Métricas",q:"Si Last Mile (bps) Hub = 36, ¿qué significa?",a:"El coste de última milla es 36 puntos base (0.36%)",opts:["El coste de última milla es 36 puntos base (0.36%)","36 minutos promedio de entrega","36 paquetes por ruta","36 estaciones activas"],explain:"36 BPS = 0.36% del valor del pedido se gasta en última milla. Es una métrica de eficiencia financiera. Menos BPS = más eficiente."},
  {cat:"Métricas",q:"Si NOV DPMO Hub = 385, ¿qué indica?",a:"385 paquetes no cargados en van por cada millón de oportunidades",opts:["385 paquetes no cargados en van por cada millón de oportunidades","385 vans disponibles","385 defectos totales del día","385 conductores activos"],explain:"385 DPMO es relativamente bajo. Con 184K paquetes/día, son ~71 paquetes que no se cargaron. Causas: no encontrados en estación, error de escaneo, o van llena."},

  // === CATEGORÍA: Rol ===
  {cat:"Rol",q:"¿Cuál es la primera tarea del día en el rol?",a:"Revisar las métricas del DBR cada mañana",opts:["Revisar las métricas del DBR cada mañana","Enviar emails a DSPs","Cargar paquetes","Revisar vehículos"],explain:"Entre 8:18-9:07 AM se revisan las métricas del día anterior, se identifican flags (alertas) y se escriben notas en las secciones con desviaciones significativas."},
  {cat:"Rol",q:"¿Qué se hace cuando hay una desviación en métricas?",a:"Se escribe un RCA note (análisis de causa raíz)",opts:["Se escribe un RCA note (análisis de causa raíz)","Se cierra la estación","Se llama al cliente","Se despide al conductor"],explain:"RCA = Root Cause Analysis. Se identifica POR QUÉ la métrica se desvió, se documenta en el DBR, y se crea un Action Item con responsable y fecha de resolución."},
  {cat:"Rol",q:"¿En qué horario se publican las notas matutinas?",a:"~8:18 - 9:07 AM",opts:["~8:18 - 9:07 AM","6:00 AM","12:00 PM","5:00 PM"],explain:"Las notas matutinas se publican temprano para que el equipo de liderazgo las vea antes de las reuniones de la mañana. Hay una actualización adicional ~11:42 AM."},
  {cat:"Rol",q:"¿Qué secciones del DBR requieren notas frecuentes?",a:"Volume SnOP y LMDX/Quality",opts:["Volume SnOP y LMDX/Quality","Safety y DEI","Finance y WFS","Launch y Expansion"],explain:"SnOP porque el volumen cambia diario y hay que explicar desviaciones vs forecast. LMDX porque la calidad impacta directamente al cliente y genera flags frecuentes."},

  // === CATEGORÍA: Otros ===
  {cat:"Otros",q:"¿Qué significa ACES?",a:"Amazon Customer Excellence System",opts:["Amazon Customer Excellence System","Automated Control and Efficiency System","Advanced Carrier Evaluation Score","Amazon Compliance and Ethics Standard"],explain:"ACES es el framework de excelencia operativa de Amazon. Se divide en 'In Station' (dentro del hub) y 'On Road' (en ruta). Mide eficiencia y calidad del proceso."},
  {cat:"Otros",q:"¿Qué es WFS?",a:"Workforce Staffing (dotación de personal)",opts:["Workforce Staffing (dotación de personal)","Warehouse Fulfillment System","Weekly Financial Summary","Work Flow Scheduler"],explain:"WFS es el equipo que recluta y gestiona el personal de las estaciones. Sus métricas (D1S, Fill Rate, LO) determinan si hay suficiente gente para operar."},
  {cat:"Otros",q:"¿Qué es RCA?",a:"Root Cause Analysis (análisis de causa raíz)",opts:["Root Cause Analysis (análisis de causa raíz)","Regional Capacity Assessment","Route Compliance Audit","Real-time Customer Alert"],explain:"Cuando una métrica falla, no basta con decir 'bajó'. Hay que encontrar la CAUSA RAÍZ: ¿fue un linehaul tardío? ¿ausentismo? ¿pico de volumen? El RCA documenta esto."},
  {cat:"Otros",q:"¿Qué es un Flag en el DBR?",a:"Alerta generada cuando una métrica cruza su umbral/target",opts:["Alerta generada cuando una métrica cruza su umbral/target","Bandera de un país","Marcador de prioridad de paquete","Señal de fin de turno"],explain:"Cada métrica tiene un target. Si First Day Delivery baja de 99%, se genera un flag rojo. Requiere RCA note y Action Item. Los flags son lo primero que se revisa en el DBR."},
  {cat:"Otros",q:"¿Qué son las Concessions?",a:"Compensaciones al cliente (reembolso o reemplazo) por fallo en entrega",opts:["Compensaciones al cliente (reembolso o reemplazo) por fallo en entrega","Descuentos a DSPs","Permisos especiales","Concesiones de espacio"],explain:"Cada concesión = dinero perdido + cliente insatisfecho. Se miden en DPMO para normalizar. Reducir concesiones es prioridad porque impacta directamente el P&L."},

  // === CATEGORÍA: S2R / Dispatch ===
  {cat:"S2R",q:"¿Qué es un nodo S2R?",a:"Store to Route - nodo donde el volumen del HUB se clasifica por Milk Run y se despacha a stores",opts:["Store to Route - nodo donde el volumen del HUB se clasifica por Milk Run y se despacha a stores","Station to Region","Sort to Receive","Ship to Return"],explain:"En S2R, los paquetes del Hub se clasifican (stow) por Milk Run y se envían a stores. Desde ahí, el DSP recoge y entrega al cliente final."},
  {cat:"S2R",q:"¿Qué es el Stow en el contexto S2R?",a:"Proceso de clasificar el volumen del HUB por Milk Run",opts:["Proceso de clasificar el volumen del HUB por Milk Run","Guardar paquetes en almacén","Cargar la furgoneta","Escanear paquetes de entrada"],explain:"Stow = clasificar cada paquete según la ruta Milk Run a la que pertenece. Hasta que no se completa el stow, NO se puede generar el Dispatch Sheet."},
  {cat:"S2R",q:"¿Qué es un Dispatch Sheet / Wave Plan?",a:"Documento con el plan de oleadas de despacho para un nodo S2R",opts:["Documento con el plan de oleadas de despacho para un nodo S2R","Hoja de ruta del conductor","Factura del envío","Contrato del DSP"],explain:"El Dispatch Sheet indica qué volumen va a cada store y en qué oleada. Se genera desde Route Planning y se envía al DSP por email."},
  {cat:"S2R",q:"¿Qué herramienta se usa para generar Dispatch Sheets?",a:"Route Planning",opts:["Route Planning","Cortex","PANDA","Harmony"],explain:"Route Planning es la herramienta interna donde se busca el nodo S2R, se confirma el stow y se descarga el Dispatch Sheet."},
  {cat:"S2R",q:"¿Qué se debe escribir en Route Planning antes de descargar el Dispatch Sheet?",a:"STOW COMPLETE",opts:["STOW COMPLETE","DOWNLOAD","READY","DISPATCH NOW"],explain:"Es obligatorio escribir 'STOW COMPLETE' en el campo de búsqueda para habilitar la descarga correcta del Dispatch Sheet."},
  {cat:"S2R",q:"¿Qué es un DILO?",a:"Day In the Life Of - documento con la rutina diaria de un nodo",opts:["Day In the Life Of - documento con la rutina diaria de un nodo","Daily Inventory Log Output","Dispatch Information Layout Order","Delivery Instruction List Official"],explain:"El DILO define los horarios clave de cada nodo: cuándo se completa el stow, cuándo se puede extraer el Dispatch Sheet, cut-offs, etc."},
  {cat:"S2R",q:"¿Qué es una GHOST Store?",a:"Store ficticia para asignar volumen donde no hay store real o la existente no puede absorberlo",opts:["Store ficticia para asignar volumen donde no hay store real o la existente no puede absorberlo","Tienda cerrada permanentemente","Store con problemas de seguridad","Store sin electricidad"],explain:"Se crea un GHOST cuando una store sale y las vecinas no pueden absorber su volumen, o cuando hay volumen en una zona sin store. El DSP asume el volumen directamente."},
  {cat:"S2R",q:"¿Cuál es la convención de nombre para GHOST stores?",a:"GHOST - XXXX (Node) - DSP - USE",opts:["GHOST - XXXX (Node) - DSP - USE","GHOST_store_001","GH-Node-Date","FANTASMA-Ciudad-Número"],explain:"Ejemplo real: GHOST - EQV8 - INDL - USE. Identifica el nodo, el DSP responsable y que está en uso activo."},
  {cat:"S2R",q:"¿Qué es Store Rostering?",a:"Proceso donde las stores confirman vía HUB App si van a trabajar o no",opts:["Proceso donde las stores confirman vía HUB App si van a trabajar o no","Lista de stores por tamaño","Ranking de stores por volumen","Asignación de stores a DSPs"],explain:"Las stores completan una encuesta en la HUB App. Si una store no trabaja, se marca en amarillo en el Dispatch Sheet para que el DSP lo sepa."},
  {cat:"S2R",q:"¿Qué se hace con las stores que no trabajan en el Dispatch Sheet?",a:"Se marcan en amarillo para que el DSP las identifique",opts:["Se marcan en amarillo para que el DSP las identifique","Se eliminan del sistema","Se reasignan a otro nodo","Se envía un email al cliente"],explain:"El supervisor marca en amarillo las stores no operativas. Así el DSP sabe que ese volumen no se puede entregar ahí y lo gestiona de otra forma."},
  {cat:"S2R",q:"¿Cuál es el formato del asunto del email con Dispatch Sheets?",a:"XXXX (node) Wave Plan OFD DD.MM.YYYY",opts:["XXXX (node) Wave Plan OFD DD.MM.YYYY","Dispatch Sheet - Node - Date","Wave Plan #ID","DS-Node-Week"],explain:"Ejemplo: 'EQV8 Wave Plan OFD 13.01.2026'. Formato estandarizado para que los DSPs identifiquen rápidamente el nodo y la fecha."},
  {cat:"S2R",q:"¿Qué equipo recibe la transición del proceso de Dispatch Sheets?",a:"LMAQ (Last Mile Account Quality)",opts:["LMAQ (Last Mile Account Quality)","ACES","WFS","Finance"],explain:"El proceso pasa de los HUB Operations Supervisors al equipo LMAQ, que se encarga de la calidad de cuentas de última milla."},
  {cat:"S2R",q:"¿Para qué sirven los QR Codes en el Dispatch Sheet?",a:"Para que el DSP los escanee durante el load-out",opts:["Para que el DSP los escanee durante el load-out","Para tracking del cliente","Para acceder al almacén","Para fichar entrada/salida"],explain:"Cada Dispatch Sheet tiene un QR que el DSP escanea al cargar la van. Confirma qué volumen se lleva y activa el tracking."},
  {cat:"S2R",q:"¿Cuántos pasos tiene el proceso diario de Dispatch Sheets?",a:"9 pasos",opts:["9 pasos","5 pasos","3 pasos","12 pasos"],explain:"1.Confirmar stow 2.Descargar de Route Planning 3.Abrir macro 4.Compilar 5.Generar QR 6.Combinar 7.Revisar rostering 8.Marcar GHOST 9.Enviar email a DSPs."},

  // === CATEGORÍA: Red de Nodos ===
  {cat:"Red de Nodos",q:"¿Qué es una Mother DS?",a:"Delivery Station principal de la que dependen los nodos hub",opts:["Delivery Station principal de la que dependen los nodos hub","La estación más grande de la red","La primera estación construida","Estación de backup"],explain:"Ejemplo: DMA4 es la Mother DS de EHM4. El hub (EHM4) opera bajo la estructura de la DS madre para temas de volumen compartido."},
  {cat:"Red de Nodos",q:"¿Qué diferencia hay entre un nodo Exclusive y uno Shared?",a:"Exclusive opera solo para Hub; Shared comparte volumen con la DS madre",opts:["Exclusive opera solo para Hub; Shared comparte volumen con la DS madre","Exclusive es más grande","Shared tiene más personal","No hay diferencia real"],explain:"EHM4 (Exclusive, 62 stores) solo procesa volumen Hub. DMA4 (Shared, 126 stores) comparte volumen entre Hub y la DS regular."},
  {cat:"Red de Nodos",q:"¿Qué es un Account Manager (AM) en el contexto Hub?",a:"Persona responsable de gestionar los nodos/stores asignados",opts:["Persona responsable de gestionar los nodos/stores asignados","Gerente de cuentas bancarias","Administrador del sistema","Manager de los conductores"],explain:"Cada AM gestiona varios nodos. Ejemplo: Ángela gestiona OCL4, OCM4, EHM4, DMA4, DMZ4, DIC1. Son el punto de contacto para operaciones del nodo."},
  {cat:"Red de Nodos",q:"¿Qué indica el número de 'Stores FY' en un nodo?",a:"Cantidad de stores (puntos de entrega) asignadas al nodo en el año fiscal",opts:["Cantidad de stores (puntos de entrega) asignadas al nodo en el año fiscal","Facturación anual","Número de empleados","Capacidad máxima de paquetes"],explain:"Ejemplo: DCT4 tiene 235 stores. Más stores = más volumen potencial y más complejidad de gestión para el AM."},
  {cat:"Red de Nodos",q:"¿Qué significa que un nodo tenga código que empieza con 'E' (ej: EHM4)?",a:"Es un nodo Hub Exclusive",opts:["Es un nodo Hub Exclusive","Es una estación de emergencia","Es un nodo europeo","Es un nodo experimental"],explain:"Los códigos E (EHM4, EQA7, EGP1) son nodos exclusivos del Hub. Los códigos D (DMA4, DCT7) son DS compartidas. Los O (OCL4, OCM4) son otros nodos compartidos."},
  {cat:"Red de Nodos",q:"¿Qué significa que un nodo tenga código que empieza con 'O' (ej: OCL4)?",a:"Es un nodo compartido (Other/Overflow)",opts:["Es un nodo compartido (Other/Overflow)","Es un nodo offline","Es un nodo obsoleto","Es un nodo de origen"],explain:"Los nodos O son puntos compartidos adicionales que procesan volumen Hub junto con otro volumen. Suelen tener menos stores que los nodos D o E."},
  // === CATEGORÍA: SOP Bulk ===
  {cat:"SOP Bulk",q:"¿A qué hora se ejecuta el Sort Planning (ADV_v4)?",a:"08:00",opts:["08:00","12:00","15:00","06:00"],explain:"El Sort Planning se genera a primera hora (08:00) ejecutando el script ADV_v4. Es requisito previo para el First Run de las 12:00."},
  {cat:"SOP Bulk",q:"¿Qué comando se ejecuta para iniciar ADV_v4?",a:"py main.py",opts:["py main.py","python adv.py","run adv_v4","npm start"],explain:"Se abre CMD en la carpeta ADV_v4 y se ejecuta 'py main.py'. Esto abre un menú con opciones."},
  {cat:"SOP Bulk",q:"¿Qué opción del menú ADV_v4 inicia la extracción automática con Chrome?",a:"Opción 2",opts:["Opción 2","Opción 1","Opción 6","Opción 3"],explain:"La Opción 2 lanza Chrome automáticamente para extraer datos de todos los nodos. Requiere login manual."},
  {cat:"SOP Bulk",q:"¿Qué se descarga en paralelo mientras ADV_v4 extrae datos?",a:"Reporte de Tiendas Activas de Salesforce",opts:["Reporte de Tiendas Activas de Salesforce","24H Forecast","Glamdring","Bulk base"],explain:"Mientras Chrome extrae, se descarga el reporte SF y se guarda en ADV_v4/data/raw como SF_YYYY-MM-DD."},
  {cat:"SOP Bulk",q:"¿Cómo se debe nombrar el archivo SF descargado para ADV_v4?",a:"SF_YYYY-MM-DD",opts:["SF_YYYY-MM-DD","report_fecha.csv","salesforce_export.csv","tiendas_activas.csv"],explain:"El formato es SF_YYYY-MM-DD (ej: SF_2026-05-28) y se guarda en la carpeta ADV_v4/data/raw."},
  {cat:"SOP Bulk",q:"¿Qué opciones se ejecutan después de que Chrome termine la extracción?",a:"Opción 1 y luego Opción 6",opts:["Opción 1 y luego Opción 6","Opción 3 y 4","Opción 5","Solo Opción 1"],explain:"Opción 1 procesa los datos extraídos. Opción 6 genera el archivo final. El resultado queda en ADV_v4/data/processed."},
  {cat:"SOP Bulk",q:"¿Dónde se genera el archivo Sort Planning del día?",a:"ADV_v4/data/processed",opts:["ADV_v4/data/processed","ADV_v4/data/raw","Downloads","Desktop"],explain:"El archivo Sort Planning DD.MM.YYYY.xlsx se genera automáticamente en la carpeta data/processed tras ejecutar las opciones 1 y 6."},
  {cat:"SOP Bulk",q:"¿Qué es lo PRIMERO que debes hacer al abrir el Bulk descargado?",a:"Cambiar la fecha a MAÑANA",opts:["Cambiar la fecha a MAÑANA","Pegar los datos de SF","Ejecutar macros","Filtrar ceros"],explain:"CRITICAL: Si no se cambia la fecha, los ramp-ups de nodos nuevos no calculan correctamente los días de tenure y se coge el volumen del día incorrecto."},
  {cat:"SOP Bulk",q:"¿Qué pasa si NO cambias la fecha del Bulk?",a:"Los ramp-ups calculan mal y se usa el volumen del día incorrecto",opts:["Los ramp-ups calculan mal y se usa el volumen del día incorrecto","No pasa nada grave","Solo afecta al formato","Se borran las macros"],explain:"Gran impacto: nodos nuevos (como DGP1) no reciben la capacidad correcta según su tenure, y el CVP se calcula con la fecha equivocada."},
  {cat:"SOP Bulk",q:"¿Qué son los nodos 'en rojo' que hay que arrastrar?",a:"Nodos nuevos que necesitan ser extendidos para lanzar en la fecha correcta",opts:["Nodos nuevos que necesitan ser extendidos para lanzar en la fecha correcta","Nodos con errores","Nodos cerrados","Nodos sin volumen"],explain:"Si no se arrastran, las tiendas de esos nodos no reciben capacidad. Se verifican al abrir el Bulk."},
  {cat:"SOP Bulk",q:"¿Cuántas fuentes de datos se consultan en el First Run?",a:"3 (Glamdring, Salesforce, 24H Forecast)",opts:["3 (Glamdring, Salesforce, 24H Forecast)","2","4","5"],explain:"Las 3 fuentes son: Glamdring (NSD Dashboard en QuickSight), Reporte Tiendas Activas (Salesforce) y 24H Forecast (QuickSight)."},
  {cat:"SOP Bulk",q:"¿Qué se descarga de Glamdring?",a:"NSD Adhoc Events (CSV con NSDs programados)",opts:["NSD Adhoc Events (CSV con NSDs programados)","Forecast de volumen","Lista de tiendas","Mapa de nodos"],explain:"Glamdring es el NSD Dashboard en QuickSight. Se descarga el CSV con todos los Non-Service Days programados por tienda."},
  {cat:"SOP Bulk",q:"¿Cómo se deben pegar los datos en el Bulk?",a:"Como VALORES y sin encabezados",opts:["Como VALORES y sin encabezados","Con formato original","Con encabezados","Como fórmulas"],explain:"Siempre pegar como valores para no arrastrar formatos externos ni romper las fórmulas del Bulk. Sin encabezados porque la fila 1 ya los tiene."},
  {cat:"SOP Bulk",q:"¿Qué filtro es CRÍTICO aplicar antes de pegar datos?",a:"Filtrar y eliminar filas con valor 0 (Ctrl+Mayús+L)",opts:["Filtrar y eliminar filas con valor 0 (Ctrl+Mayús+L)","Filtrar por fecha","Filtrar por nodo","Ordenar alfabéticamente"],explain:"Las filas con valor 0 deben eliminarse. Si se dejan, distorsionan los cálculos de capacidad. Se usa Ctrl+Mayús+L para activar filtros."},
  {cat:"SOP Bulk",q:"¿De dónde se extrae la info para actualizar Cap Utilization?",a:"Pestaña SP del archivo Sort Planning",opts:["Pestaña SP del archivo Sort Planning","Pestaña CVP","24H Forecast","Salesforce"],explain:"Se abre el Sort Planning del día, se va a la pestaña SP, se copia todo y se pega DEBAJO de la última fila en Cap Utilization del Bulk."},
  {cat:"SOP Bulk",q:"¿Cap Utilization se borra antes de pegar datos nuevos?",a:"No, se acumula (se pega debajo de la última fila)",opts:["No, se acumula (se pega debajo de la última fila)","Sí, se borra todo","Se borra solo la última semana","Se reemplaza todo"],explain:"Cap Utilization es acumulado histórico. Cada día se añaden ~4200 filas nuevas debajo de las existentes. Nunca se borra."},
  {cat:"SOP Bulk",q:"¿Cuál es el valor máximo permitido del 24H Adjustment Factor?",a:"1.3",opts:["1.3","1.5","2.0","1.1"],explain:"El factor máximo es 1.3. Se usa para ajustar el forecast cuando se espera más volumen del previsto. No se puede superar este límite."},
  {cat:"SOP Bulk",q:"¿Cuál es el valor máximo permitido del Min ADV?",a:"80",opts:["80","100","120","60"],explain:"Min ADV no puede superar 80. Es el volumen diario promedio mínimo que se asigna a cada partner. Rango permitido: 37-80."},
  {cat:"SOP Bulk",q:"¿Cuál es el valor máximo permitido del Max ADV?",a:"120",opts:["120","100","150","80"],explain:"Max ADV máximo es 120. Es el tope de paquetes que se asigna a un partner. Rango permitido: 70-120."},
  {cat:"SOP Bulk",q:"¿Qué porcentaje NO debe superar el Flex Up vs CVP?",a:"±15%",opts:["±15%","±10%","±20%","±5%"],explain:"Si el Flex Up supera ±15%, indica que el volumen asignado se desvía demasiado del plan (CVP). Hay que ajustar parámetros."},
  {cat:"SOP Bulk",q:"¿A qué hora se ejecuta el paso de NSD Slack?",a:"15:00",opts:["15:00","12:00","08:00","17:00"],explain:"A las 15:00 se extrae el archivo de Slack, se ejecuta el script NSDslackv2 y se actualiza el Bulk con los datos procesados."},
  {cat:"SOP Bulk",q:"¿Qué comando se usa en Slack para exportar NSDs?",a:"/export [fecha-inicio] [fecha-fin]",opts:["/export [fecha-inicio] [fecha-fin]","/download nsd","/get-nsd-data","/extract audits"],explain:"En el canal nsd-audits-es se ejecuta /export con un rango de 3 días. Se espera a que cargue completamente antes de descargar."},
  {cat:"SOP Bulk",q:"¿Qué hace el script NSDslackv2?",a:"Parsea el CSV crudo de Slack y genera una tabla limpia con 8 columnas",opts:["Parsea el CSV crudo de Slack y genera una tabla limpia con 8 columnas","Envía mensajes a Slack","Descarga archivos de Slack","Crea el TT automáticamente"],explain:"El script toma el export crudo de Slack (mensajes con formato texto) y lo convierte en un CSV estructurado con: UPDATED AT, TYPE, STORE ID, STORE NAME, STATION CODE, NSD START DATE, NSD END DATE, REQUESTED BY."},
  {cat:"SOP Bulk",q:"¿Qué tipo de TT se crea en River?",a:"Supply Window Max Capacity Change",opts:["Supply Window Max Capacity Change","Volume Adjustment Request","Capacity Override","Store Launch Request"],explain:"El TT se configura con Type=Supply Window Max Capacity Change, Bulk Type=Ad Hoc SW Max Capacity Change, y fecha de MAÑANA."},
  {cat:"SOP Bulk",q:"¿Qué archivo se adjunta en el TT?",a:"El MCO (archivo CSV)",opts:["El MCO (archivo CSV)","El Bulk completo (.xlsm)","Un PDF resumen","Un screenshot"],explain:"El MCO es el CSV que se genera del Bulk y se adjunta en la página final del SIM antes de hacer clic en Submit ticket. Sin él, el LMAQ no puede aprobar."},
  {cat:"SOP Bulk",q:"¿Qué es el colchón de seguridad sobre el CVP?",a:"+200 a +800 paquetes según tamaño del nodo",opts:["+200 a +800 paquetes según tamaño del nodo","+100 fijo","No se necesita colchón","+1000 siempre"],explain:"Se pierden paquetes en la secuenciación del día. El Final Admiral debe estar por encima del CVP: +200-300 (nodos pequeños) hasta +500-800 (nodos muy grandes)."},
  {cat:"SOP Bulk",q:"¿Con qué frecuencia se actualiza la pestaña Launches W-0?",a:"1 vez por semana",opts:["1 vez por semana","Diariamente","Cada 2 semanas","Mensualmente"],explain:"Se actualiza semanalmente con los lanzamientos de la semana (normalmente miércoles y jueves). Si no se actualiza, tiendas nuevas no reciben capacidad."},
  {cat:"SOP Bulk",q:"¿Qué color tienen las tabs de actualización semanal en el Bulk?",a:"Amarillas",opts:["Amarillas","Azules","Rojas","Verdes"],explain:"Tabs amarillas = actualización semanal. Tabs azules = actualización diaria. Es importante no confundirlas."},
  {cat:"SOP Bulk",q:"¿Qué color tienen las tabs de actualización diaria en el Bulk?",a:"Azules",opts:["Azules","Amarillas","Rojas","Verdes"],explain:"Tabs azules = actualización diaria (Glamdring, sf, 24h forecast, cap utilization, NSD Slack). Tabs amarillas = semanal."},
  // === CATEGORÍA: SOP Hub Hero ===
  {cat:"SOP Hub Hero",q:"¿Cuál es el primer paso para actualizar Hub Hero?",a:"Ejecutar ADV_v4 para generar el Sort Planning",opts:["Ejecutar ADV_v4 para generar el Sort Planning","Abrir el dashboard","Descargar de SharePoint","Enviar email al equipo"],explain:"Hub Hero necesita los datos del Sort Planning. Primero se ejecuta ADV_v4 (mismos pasos que para el Bulk) y luego se usa el resultado."},
  {cat:"SOP Hub Hero",q:"¿Cómo se llama el archivo maestro de Hub Hero?",a:"hub hero.xlsx",opts:["hub hero.xlsx","dashboard.xlsx","hub_hero_master.xlsm","hero_data.xlsx"],explain:"El archivo maestro está en la carpeta '7. HUB hero' dentro de la carpeta compartida de Network & Planning."},
  {cat:"SOP Hub Hero",q:"¿En qué pestaña de hub hero.xlsx se pegan los datos?",a:"Sort planning",opts:["Sort planning","Dashboard","Data","SP"],explain:"Se va a la pestaña 'Sort planning', se borran los datos desde fila 2 y se pegan los nuevos como valores desde A2."},
  {cat:"SOP Hub Hero",q:"¿Qué comando genera el dashboard interactivo de Hub Hero?",a:"py ejecutar_hub_hero.pyw",opts:["py ejecutar_hub_hero.pyw","py main.py","py dashboard.py","py generate.py"],explain:"Se abre CMD en la carpeta '7. HUB hero' y se ejecuta 'py ejecutar_hub_hero.pyw'. Genera dashboard_interactive.html."},
  {cat:"SOP Hub Hero",q:"¿Cómo se llama el archivo HTML que genera Hub Hero?",a:"dashboard_interactive.html",opts:["dashboard_interactive.html","hub_hero.html","ES_HUB_HERO.html","index.html"],explain:"El script genera automáticamente dashboard_interactive.html en la misma carpeta. Luego se copia a la carpeta compartida."},
  {cat:"SOP Hub Hero",q:"¿Cómo se debe renombrar el archivo al subirlo a la carpeta compartida?",a:"ES HUB HERO (sin extensión .html)",opts:["ES HUB HERO (sin extensión .html)","dashboard_interactive.html","HUB_HERO_v2","ES_Hub_Hero.html"],explain:"Se renombra a 'ES HUB HERO' sin la extensión .html para que coincida con el nombre que los supervisores esperan encontrar."},
  {cat:"SOP Hub Hero",q:"¿Qué se hace con el archivo antiguo antes de subir el nuevo?",a:"Se borra (o se guarda en backup)",opts:["Se borra (o se guarda en backup)","Se renombra con fecha","Se deja junto al nuevo","No se toca"],explain:"Se localiza y borra el archivo existente 'ES HUB HERO' en la carpeta compartida, y luego se pega el nuevo."},
  {cat:"SOP Hub Hero",q:"¿Por qué es importante pegar como valores en hub hero.xlsx?",a:"Para no arrastrar formatos externos ni romper fórmulas del archivo maestro",opts:["Para no arrastrar formatos externos ni romper fórmulas del archivo maestro","Por velocidad","Por tamaño de archivo","No es importante"],explain:"El archivo maestro tiene fórmulas que dependen de los datos pegados. Si se pega con formato, puede romper esas fórmulas o cambiar el layout."},
];
